import { useState, useRef } from "react";

// ─── Palette ──────────────────────────────────────────────────────────────────
const DARK = {
  bg:          "#0f1117",
  surface:     "#181c27",
  surfaceUp:   "#1e2336",
  border:      "#252d42",
  borderHover: "#3a4460",
  text:        "#e2e8f4",
  sub:         "#7a8aaa",
  muted:       "#3a4460",
  blue:        "#4f80ff",
  blueDim:     "#1e3070",
  green:       "#3ecf8e",
  greenDim:    "#0d3325",
  red:         "#f56565",
  redDim:      "#3d1515",
  amber:       "#f6a623",
  amberDim:    "#3d2a08",
  nav:         "rgba(15,17,23,0.94)",
};

const LIGHT = {
  bg:          "#f8f9fc",
  surface:     "#ffffff",
  surfaceUp:   "#f0f3fa",
  border:      "#dde3f0",
  borderHover: "#b0bcda",
  text:        "#0f1520",
  sub:         "#5a6a8a",
  muted:       "#c0cce0",
  blue:        "#2563eb",
  blueDim:     "#dbeafe",
  green:       "#16a34a",
  greenDim:    "#dcfce7",
  red:         "#dc2626",
  redDim:      "#fee2e2",
  amber:       "#d97706",
  amberDim:    "#fef3c7",
  nav:         "rgba(248,249,252,0.94)",
};

// ─── Tiny icon set ────────────────────────────────────────────────────────────
const Ic = ({ d, size = 16, color = "currentColor", fill = "none", sw = 1.8 }) => (
  <svg width={size} height={size} viewBox="0 0 24 24" fill={fill} stroke={color}
    strokeWidth={sw} strokeLinecap="round" strokeLinejoin="round">
    {typeof d === "string" ? <path d={d} /> : d}
  </svg>
);

const ICONS = {
  home:     "M3 9l9-7 9 7v11a2 2 0 01-2 2H5a2 2 0 01-2-2z",
  doc:      [<path key="a" d="M14 2H6a2 2 0 00-2 2v16a2 2 0 002 2h12a2 2 0 002-2V8z"/>, <polyline key="b" points="14,2 14,8 20,8"/>],
  shield:   "M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10z",
  camera:   [<path key="a" d="M23 19a2 2 0 01-2 2H3a2 2 0 01-2-2V8a2 2 0 012-2h4l2-3h6l2 3h4a2 2 0 012 2z"/>, <circle key="b" cx="12" cy="13" r="4"/>],
  search:   [<circle key="a" cx="11" cy="11" r="8"/>, <line key="b" x1="21" y1="21" x2="16.65" y2="16.65"/>],
  sun:      [<circle key="a" cx="12" cy="12" r="5"/>, ...[0,45,90,135,180,225,270,315].map((a,i) => { const r=a*Math.PI/180; return <line key={i} x1={12+7*Math.sin(r)} y1={12-7*Math.cos(r)} x2={12+9*Math.sin(r)} y2={12-9*Math.cos(r)}/>; })],
  moon:     "M21 12.79A9 9 0 1111.21 3 7 7 0 0021 12.79z",
  menu:     [<line key="a" x1="3" y1="6" x2="21" y2="6"/>, <line key="b" x1="3" y1="12" x2="21" y2="12"/>, <line key="c" x1="3" y1="18" x2="21" y2="18"/>],
  x:        [<line key="a" x1="18" y1="6" x2="6" y2="18"/>, <line key="b" x1="6" y1="6" x2="18" y2="18"/>],
  upload:   [<polyline key="a" points="16,16 12,12 8,16"/>, <line key="b" x1="12" y1="12" x2="12" y2="21"/>, <path key="c" d="M20.39 18.39A5 5 0 0018 9h-1.26A8 8 0 103 16.3"/>],
  arrow:    [<line key="a" x1="5" y1="12" x2="19" y2="12"/>, <polyline key="b" points="12,5 19,12 12,19"/>],
  check:    <polyline points="20,6 9,17 4,12"/>,
  alert:    [<polygon key="a" points="10.29,3.86 1.82,18 22.18,18 13.71,3.86"/>, <line key="b" x1="12" y1="9" x2="12" y2="13"/>, <line key="c" x1="12" y1="17" x2="12.01" y2="17"/>],
  spin:     [<line key="a" x1="12" y1="2" x2="12" y2="6"/>, <line key="b" x1="12" y1="18" x2="12" y2="22"/>, <line key="c" x1="4.93" y1="4.93" x2="7.76" y2="7.76"/>, <line key="d" x1="16.24" y1="16.24" x2="19.07" y2="19.07"/>, <line key="e" x1="2" y1="12" x2="6" y2="12"/>, <line key="f" x1="18" y1="12" x2="22" y2="12"/>, <line key="g" x1="4.93" y1="19.07" x2="7.76" y2="16.24"/>, <line key="h" x1="16.24" y1="7.76" x2="19.07" y2="4.93"/>],
  scale:    [<line key="a" x1="12" y1="1" x2="12" y2="23"/>, <path key="b" d="M17 5H9.5a3.5 3.5 0 000 7h5a3.5 3.5 0 010 7H6"/>],
  external: [<path key="a" d="M18 13v6a2 2 0 01-2 2H5a2 2 0 01-2-2V8a2 2 0 012-2h6"/>, <polyline key="b" points="15,3 21,3 21,9"/>, <line key="c" x1="10" y1="14" x2="21" y2="3"/>],
};

// ─── Helpers ──────────────────────────────────────────────────────────────────
const Spinner = ({ c }) => (
  <span style={{ display:"inline-block", animation:"spin 1s linear infinite" }}>
    <Ic d={ICONS.spin} size={15} color={c} />
  </span>
);

const Tag = ({ label, variant, t }) => {
  const map = {
    success: { bg: t.greenDim, fg: t.green },
    danger:  { bg: t.redDim,   fg: t.red },
    warning: { bg: t.amberDim, fg: t.amber },
    info:    { bg: t.blueDim,  fg: t.blue },
  };
  const s = map[variant] || map.info;
  return (
    <span style={{ padding:"2px 9px", borderRadius:99, fontSize:11, fontWeight:600,
      background:s.bg, color:s.fg, letterSpacing:"0.01em", whiteSpace:"nowrap" }}>
      {label}
    </span>
  );
};

const Btn = ({ onClick, disabled, loading, children, small, outline, t }) => (
  <button onClick={onClick} disabled={disabled} style={{
    padding: small ? "8px 16px" : "10px 22px",
    borderRadius: 8,
    fontSize: 13,
    fontWeight: 600,
    fontFamily: "inherit",
    cursor: disabled ? "not-allowed" : "pointer",
    border: outline ? `1.5px solid ${t.border}` : "none",
    background: disabled ? t.surfaceUp : outline ? "transparent" : t.blue,
    color: disabled ? t.sub : outline ? t.sub : "#fff",
    display: "inline-flex", alignItems: "center", gap: 7,
    transition: "all 0.15s",
    opacity: disabled ? 0.5 : 1,
    letterSpacing: "0.01em",
  }}>
    {loading && <Spinner c={disabled ? t.sub : "#fff"} />}
    {children}
  </button>
);

const Input = ({ value, onChange, onKeyDown, placeholder, t }) => (
  <input value={value} onChange={onChange} onKeyDown={onKeyDown} placeholder={placeholder}
    style={{
      background: t.surfaceUp, border: `1.5px solid ${t.border}`,
      borderRadius: 8, padding: "10px 14px", color: t.text,
      fontSize: 14, fontFamily: "inherit", outline: "none",
      width: "100%", boxSizing: "border-box",
    }} />
);

const Textarea = ({ value, onChange, placeholder, rows, t }) => (
  <textarea value={value} onChange={onChange} placeholder={placeholder} rows={rows}
    style={{
      background: t.surfaceUp, border: `1.5px solid ${t.border}`,
      borderRadius: 8, padding: "10px 14px", color: t.text,
      fontSize: 14, fontFamily: "inherit", outline: "none",
      width: "100%", boxSizing: "border-box", resize: "vertical",
    }} />
);

const Card = ({ children, t, style }) => (
  <div style={{
    background: t.surface, border: `1.5px solid ${t.border}`,
    borderRadius: 12, padding: "24px 26px",
    ...style,
  }}>
    {children}
  </div>
);

const SectionTitle = ({ children, t }) => (
  <h3 style={{ fontSize: 13, fontWeight: 700, color: t.sub, letterSpacing: "0.06em",
    textTransform: "uppercase", margin: "0 0 16px" }}>
    {children}
  </h3>
);

const PageTitle = ({ icon, title, desc, t }) => (
  <div style={{ marginBottom: 36 }}>
    <div style={{ display: "flex", alignItems: "center", gap: 10, marginBottom: 6 }}>
      <Ic d={ICONS[icon]} size={20} color={t.blue} />
      <h1 style={{ fontSize: 22, fontWeight: 700, color: t.text, margin: 0 }}>{title}</h1>
    </div>
    <p style={{ fontSize: 14, color: t.sub, margin: 0, lineHeight: 1.6 }}>{desc}</p>
  </div>
);

const ErrBox = ({ msg, t }) => (
  <div style={{ padding:"12px 16px", borderRadius:8, background:t.redDim,
    border:`1px solid ${t.red}40`, color:t.red, fontSize:13,
    display:"flex", gap:8, alignItems:"center", marginBottom:16 }}>
    <Ic d={ICONS.alert} size={14} color={t.red} /> {msg}
  </div>
);

// ─── Drop Zone ────────────────────────────────────────────────────────────────
const DropZone = ({ onFile, accept, hint, t }) => {
  const [drag, setDrag] = useState(false);
  const [file, setFile] = useState(null);
  const ref = useRef();
  const pick = f => { setFile(f); onFile(f); };

  return (
    <div onClick={() => ref.current.click()}
      onDragOver={e => { e.preventDefault(); setDrag(true); }}
      onDragLeave={() => setDrag(false)}
      onDrop={e => { e.preventDefault(); setDrag(false); pick(e.dataTransfer.files[0]); }}
      style={{
        border: `1.5px dashed ${drag ? t.blue : t.border}`,
        borderRadius: 10, padding: "28px 20px", textAlign: "center",
        cursor: "pointer", background: drag ? t.blueDim + "30" : t.surfaceUp,
        transition: "all 0.15s",
      }}>
      <input ref={ref} type="file" accept={accept} style={{ display:"none" }}
        onChange={e => pick(e.target.files[0])} />
      <Ic d={ICONS.upload} size={22} color={drag ? t.blue : t.sub} />
      {file
        ? <p style={{ margin:"10px 0 0", fontSize:13, color:t.text, fontWeight:500 }}>{file.name}</p>
        : <>
            <p style={{ margin:"10px 0 4px", fontSize:14, fontWeight:500, color:t.text }}>
              Drop file here or <span style={{ color:t.blue }}>browse</span>
            </p>
            <p style={{ margin:0, fontSize:12, color:t.sub }}>{hint}</p>
          </>
      }
    </div>
  );
};

// ─── Toast ────────────────────────────────────────────────────────────────────
const Toast = ({ msg, type, t, onClose }) => {
  const c = type === "success" ? t.green : type === "error" ? t.red : t.amber;
  return (
    <div style={{
      position:"fixed", bottom:24, right:24, zIndex:9999,
      background:t.surface, border:`1.5px solid ${t.border}`,
      borderLeft:`3px solid ${c}`, borderRadius:10,
      padding:"12px 18px", maxWidth:340,
      boxShadow:"0 8px 30px rgba(0,0,0,0.25)",
      display:"flex", alignItems:"center", gap:10,
      animation:"slideUp 0.25s ease",
    }}>
      <Ic d={type === "success" ? ICONS.check : ICONS.alert} size={14} color={c} />
      <span style={{ color:t.text, fontSize:13, flex:1 }}>{msg}</span>
      <button onClick={onClose} style={{ background:"none", border:"none", cursor:"pointer", color:t.sub, padding:0 }}>
        <Ic d={ICONS.x} size={13} />
      </button>
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
// HOME
// ══════════════════════════════════════════════════════════════════════════════
const Home = ({ t, go }) => {
  const features = [
    {
      icon: "doc", page: "analyzer",
      title: "Document Analyzer",
      desc: "Upload a contract, FIR, or legal notice. Get a plain-language risk breakdown, clause by clause.",
      status: "500 error", sv: "danger",
    },
    {
      icon: "shield", page: "compliance",
      title: "Compliance Checker",
      desc: "Paste any text with old IPC references. See the corresponding BNS, BNSS, and BSA sections instantly.",
      status: "Working", sv: "success",
    },
    {
      icon: "camera", page: "evidence",
      title: "Evidence Certificate",
      desc: "Generate a BSA Section 63 certificate for digital photos — with SHA-256 hash and EXIF metadata.",
      status: "Working", sv: "success",
    },
    {
      icon: "search", page: "caselaws",
      title: "Case Laws",
      desc: "Search Indian judgments by topic. Powered by IndianKanoon with Llama-3 summaries.",
      status: "Working", sv: "success",
    },
  ];

  return (
    <div style={{ maxWidth:1000, margin:"0 auto", padding:"64px 24px" }}>

      {/* Hero */}
      <div style={{ marginBottom:64 }}>
        <div style={{ display:"flex", alignItems:"center", gap:8, marginBottom:16 }}>
          <Ic d={ICONS.scale} size={18} color={t.blue} />
          <span style={{ fontSize:13, color:t.sub, fontWeight:500 }}>Indian Legal AI</span>
        </div>
        <h1 style={{
          fontSize:"clamp(2rem, 4.5vw, 3rem)", fontWeight:800,
          color:t.text, lineHeight:1.15, margin:"0 0 16px",
          letterSpacing:"-0.02em",
        }}>
          Legal research,<br />
          <span style={{ color:t.blue }}>without the complexity.</span>
        </h1>
        <p style={{ fontSize:16, color:t.sub, maxWidth:480, lineHeight:1.75, margin:"0 0 28px" }}>
          Built to handle IPC → BNS migration, document risk analysis, evidence certification, and case law research — all running locally on your machine.
        </p>
        <div style={{ display:"flex", gap:8, flexWrap:"wrap" }}>
          {[["3,254 KB chunks", "success"], ["70+ IPC mappings", "info"], ["Llama-3 local", "info"], ["RTX 4050", "info"]].map(([l, v]) => (
            <Tag key={l} label={l} variant={v} t={t} />
          ))}
        </div>
      </div>

      {/* Cards */}
      <div style={{ display:"grid", gridTemplateColumns:"repeat(auto-fit, minmax(220px, 1fr))", gap:16 }}>
        {features.map(f => (
          <button key={f.page} onClick={() => go(f.page)} style={{
            background:t.surface, border:`1.5px solid ${t.border}`,
            borderRadius:12, padding:"22px 20px", textAlign:"left",
            cursor:"pointer", transition:"all 0.15s",
          }}
            onMouseEnter={e => { e.currentTarget.style.borderColor = t.borderHover; e.currentTarget.style.transform = "translateY(-1px)"; }}
            onMouseLeave={e => { e.currentTarget.style.borderColor = t.border; e.currentTarget.style.transform = "translateY(0)"; }}>
            <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", marginBottom:14 }}>
              <Ic d={ICONS[f.icon]} size={20} color={t.blue} />
              <Tag label={f.status} variant={f.sv} t={t} />
            </div>
            <div style={{ fontSize:15, fontWeight:700, color:t.text, marginBottom:8 }}>{f.title}</div>
            <p style={{ fontSize:13, color:t.sub, lineHeight:1.65, margin:"0 0 16px" }}>{f.desc}</p>
            <div style={{ display:"flex", alignItems:"center", gap:4, fontSize:12, color:t.blue, fontWeight:600 }}>
              Open <Ic d={ICONS.arrow} size={12} color={t.blue} />
            </div>
          </button>
        ))}
      </div>

      {/* System row */}
      <div style={{ marginTop:56, paddingTop:24, borderTop:`1px solid ${t.border}` }}>
        <p style={{ fontSize:12, color:t.muted, margin:0 }}>
          Running on OMEN laptop · Intel i7 · RTX 4050 6GB · ChromaDB · FastAPI 8001 · WhatsApp via Twilio
        </p>
      </div>
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
// ANALYZER
// ══════════════════════════════════════════════════════════════════════════════
const Analyzer = ({ t, toast }) => {
  const [file, setFile]     = useState(null);
  const [loading, setLoad]  = useState(false);
  const [result, setResult] = useState(null);
  const [err, setErr]       = useState(null);
  const [q, setQ]           = useState("");
  const [qaLoad, setQaLoad] = useState(false);
  const [ans, setAns]       = useState(null);

  const run = async () => {
    setLoad(true); setErr(null); setResult(null);
    try {
      const fd = new FormData(); fd.append("file", file);
      const r = await fetch("http://localhost:8001/api/analyze", { method:"POST", body:fd });
      if (!r.ok) throw new Error(`Server error ${r.status}`);
      setResult(await r.json());
      toast("Analysis complete", "success");
    } catch(e) { setErr(e.message); toast(e.message, "error"); }
    finally { setLoad(false); }
  };

  const ask = async () => {
    if (!q || !result?.session_id) return;
    setQaLoad(true); setAns(null);
    try {
      const r = await fetch("http://localhost:8001/api/qa", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ question:q, session_id:result.session_id }),
      });
      setAns((await r.json()).answer);
    } catch(e) { toast("QA failed: " + e.message, "error"); }
    finally { setQaLoad(false); }
  };

  return (
    <div style={{ maxWidth:820, margin:"0 auto", padding:"52px 24px" }}>
      <PageTitle icon="doc" title="Document Analyzer"
        desc="Upload a PDF or image. The model reads every clause and flags risk — Safe, Caution, High Risk, or Illegal."
        t={t} />

      <Card t={t} style={{ marginBottom:20 }}>
        <DropZone onFile={setFile} accept=".pdf,.png,.jpg,.jpeg"
          hint="PDF, PNG, or JPEG — contract, FIR, notice, loan doc" t={t} />
        <div style={{ marginTop:14 }}>
          <Btn onClick={run} disabled={!file || loading} loading={loading} t={t}>
            {loading ? "Analyzing…" : "Run Analysis"}
          </Btn>
        </div>
      </Card>

      {err && <ErrBox msg={err} t={t} />}

      {result && <>
        <Card t={t} style={{ marginBottom:16 }}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:14 }}>
            <SectionTitle t={t}>Summary</SectionTitle>
            {result.overall_risk && <Tag label={result.overall_risk} variant={result.overall_risk === "Safe" ? "success" : "danger"} t={t} />}
          </div>
          <p style={{ color:t.sub, lineHeight:1.75, margin:0, fontSize:14 }}>{result.summary || "No summary returned."}</p>
        </Card>

        {result.clauses?.length > 0 && (
          <Card t={t} style={{ marginBottom:16 }}>
            <SectionTitle t={t}>Clauses — {result.clauses.length} found</SectionTitle>
            <div style={{ display:"flex", flexDirection:"column", gap:10 }}>
              {result.clauses.map((cl, i) => (
                <div key={i} style={{ padding:"12px 14px", borderRadius:8,
                  border:`1px solid ${t.border}`, background:t.surfaceUp }}>
                  <div style={{ display:"flex", justifyContent:"space-between", marginBottom:6 }}>
                    <span style={{ fontSize:11, color:t.muted, fontWeight:600, textTransform:"uppercase", letterSpacing:"0.05em" }}>Clause {i+1}</span>
                    <Tag label={cl.risk_level || "Unknown"} variant={cl.risk_level === "Safe" ? "success" : cl.risk_level === "Caution" ? "warning" : "danger"} t={t} />
                  </div>
                  <p style={{ color:t.text, fontSize:13, margin:"0 0 4px", lineHeight:1.65 }}>{cl.text}</p>
                  {cl.explanation && <p style={{ color:t.sub, fontSize:12, margin:0, fontStyle:"italic" }}>{cl.explanation}</p>}
                </div>
              ))}
            </div>
          </Card>
        )}

        <Card t={t}>
          <SectionTitle t={t}>Ask about this document</SectionTitle>
          <div style={{ display:"flex", gap:8 }}>
            <Input value={q} onChange={e => setQ(e.target.value)}
              onKeyDown={e => e.key === "Enter" && ask()}
              placeholder="e.g. What are the termination conditions?" t={t} />
            <Btn onClick={ask} disabled={qaLoad || !q} loading={qaLoad} small t={t}>
              {!qaLoad && <Ic d={ICONS.arrow} size={14} color="#fff" />}
            </Btn>
          </div>
          {ans && (
            <div style={{ marginTop:14, padding:"14px 16px", borderRadius:8,
              background:t.surfaceUp, border:`1px solid ${t.border}`,
              color:t.text, fontSize:14, lineHeight:1.75 }}>
              {ans}
            </div>
          )}
        </Card>
      </>}
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
// COMPLIANCE
// ══════════════════════════════════════════════════════════════════════════════
const Compliance = ({ t, toast }) => {
  const [mode, setMode]     = useState("text");
  const [text, setText]     = useState("");
  const [file, setFile]     = useState(null);
  const [loading, setLoad]  = useState(false);
  const [result, setResult] = useState(null);

  const run = async () => {
    setLoad(true); setResult(null);
    try {
      let r;
      if (mode === "text") {
        r = await fetch("http://localhost:8001/api/compliance", {
          method:"POST", headers:{"Content-Type":"application/json"},
          body: JSON.stringify({ text }),
        });
      } else {
        const fd = new FormData(); fd.append("file", file);
        r = await fetch("http://localhost:8001/api/compliance/upload", { method:"POST", body:fd });
      }
      if (!r.ok) throw new Error(`Server error ${r.status}`);
      setResult(await r.json());
      toast("Compliance check done", "success");
    } catch(e) { toast(e.message, "error"); }
    finally { setLoad(false); }
  };

  return (
    <div style={{ maxWidth:820, margin:"0 auto", padding:"52px 24px" }}>
      <PageTitle icon="shield" title="Compliance Checker"
        desc="Check which IPC sections in a document need to be updated to BNS, BNSS, or BSA — with a compliance score."
        t={t} />

      <Card t={t} style={{ marginBottom:20 }}>
        <div style={{ display:"flex", gap:6, marginBottom:18 }}>
          {[["text","Text"], ["pdf","PDF"]].map(([v,l]) => (
            <button key={v} onClick={() => setMode(v)} style={{
              padding:"6px 16px", borderRadius:6, fontSize:13, fontWeight:600,
              cursor:"pointer", fontFamily:"inherit",
              border:`1.5px solid ${mode===v ? t.blue : t.border}`,
              background: mode===v ? t.blueDim : "transparent",
              color: mode===v ? t.blue : t.sub,
              transition:"all 0.15s",
            }}>{l}</button>
          ))}
        </div>

        {mode === "text"
          ? <Textarea value={text} onChange={e => setText(e.target.value)} rows={5}
              placeholder={"Paste text with IPC references\ne.g. accused charged u/s 406, 420 IPC"}
              t={t} />
          : <DropZone onFile={setFile} accept=".pdf" hint="PDF only" t={t} />
        }
        <div style={{ marginTop:14 }}>
          <Btn onClick={run} disabled={loading || (mode==="text" ? !text : !file)} loading={loading} t={t}>
            {loading ? "Checking…" : "Check Compliance"}
          </Btn>
        </div>
      </Card>

      {result && (
        <Card t={t}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:18 }}>
            <SectionTitle t={t}>Result</SectionTitle>
            <div style={{ display:"flex", alignItems:"center", gap:10 }}>
              {result.score != null && (
                <span style={{ fontSize:24, fontWeight:800, letterSpacing:"-0.02em",
                  color: result.score >= 70 ? t.green : result.score >= 40 ? t.amber : t.red }}>
                  {result.score}
                </span>
              )}
              {result.grade && <Tag label={`Grade ${result.grade}`} variant={result.grade === "A" ? "success" : "warning"} t={t} />}
            </div>
          </div>

          {result.mappings?.length > 0 && (
            <div style={{ overflowX:"auto" }}>
              <table style={{ width:"100%", borderCollapse:"collapse", fontSize:13 }}>
                <thead>
                  <tr>
                    {["IPC Section","BNS / BNSS / BSA","Status"].map(h => (
                      <th key={h} style={{ padding:"8px 12px", textAlign:"left",
                        color:t.sub, fontSize:11, fontWeight:700,
                        textTransform:"uppercase", letterSpacing:"0.05em",
                        borderBottom:`1px solid ${t.border}` }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {result.mappings.map((m,i) => (
                    <tr key={i}>
                      <td style={{ padding:"9px 12px", color:t.blue, fontFamily:"monospace", fontWeight:600, borderBottom:`1px solid ${t.border}` }}>{m.ipc}</td>
                      <td style={{ padding:"9px 12px", color:t.text, borderBottom:`1px solid ${t.border}` }}>{m.bns || "—"}</td>
                      <td style={{ padding:"9px 12px", borderBottom:`1px solid ${t.border}` }}><Tag label={m.status || "Mapped"} variant="success" t={t} /></td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}

          {result.message && (
            <p style={{ marginTop:14, fontSize:13, color:t.sub, lineHeight:1.7, margin:0, borderTop:`1px solid ${t.border}`, paddingTop:14 }}>
              {result.message}
            </p>
          )}
        </Card>
      )}
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
// EVIDENCE
// ══════════════════════════════════════════════════════════════════════════════
const Evidence = ({ t, toast }) => {
  const [file, setFile]     = useState(null);
  const [loading, setLoad]  = useState(false);
  const [cert, setCert]     = useState(null);

  const run = async () => {
    setLoad(true); setCert(null);
    try {
      const fd = new FormData(); fd.append("image", file);
      const r = await fetch("http://localhost:8001/api/evidence", { method:"POST", body:fd });
      if (!r.ok) throw new Error(`Server error ${r.status}`);
      setCert(await r.json());
      toast("Certificate generated", "success");
    } catch(e) { toast(e.message, "error"); }
    finally { setLoad(false); }
  };

  return (
    <div style={{ maxWidth:760, margin:"0 auto", padding:"52px 24px" }}>
      <PageTitle icon="camera" title="Evidence Certificate"
        desc="Upload a photo to generate a BSA Section 63 certificate. SHA-256 hash is computed before any processing — chain of custody intact."
        t={t} />

      <Card t={t} style={{ marginBottom:20 }}>
        <DropZone onFile={setFile} accept=".jpg,.jpeg,.png,.webp"
          hint="JPG, PNG, or WebP images" t={t} />
        <div style={{ marginTop:14 }}>
          <Btn onClick={run} disabled={!file || loading} loading={loading} t={t}>
            {loading ? "Generating…" : "Generate Certificate"}
          </Btn>
        </div>
      </Card>

      {cert && (
        <Card t={t}>
          <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:18 }}>
            <SectionTitle t={t}>Certificate Details</SectionTitle>
            <Tag label="BSA § 63" variant="success" t={t} />
          </div>

          <div style={{ display:"grid", gridTemplateColumns:"1fr 1fr", gap:12 }}>
            {[
              ["SHA-256", cert.sha256, "span 2", "mono"],
              ["File",     cert.filename],
              ["Cert ID",  cert.cert_id],
              ["Timestamp",cert.timestamp],
              ["Device",   cert.exif?.device || "Not recorded"],
              ["GPS",      cert.exif?.gps    || "Not available"],
            ].map(([l, v, span, font]) => (
              <div key={l} style={{ gridColumn:span||"auto", padding:"11px 14px",
                borderRadius:8, background:t.surfaceUp, border:`1px solid ${t.border}` }}>
                <div style={{ fontSize:10, color:t.muted, fontWeight:700,
                  textTransform:"uppercase", letterSpacing:"0.08em", marginBottom:4 }}>{l}</div>
                <div style={{ fontSize:13, color:t.text, wordBreak:"break-all",
                  fontFamily: font === "mono" ? "monospace" : "inherit" }}>{v || "—"}</div>
              </div>
            ))}
          </div>

          {cert.pdf_url && (
            <div style={{ marginTop:18 }}>
              <a href={`http://localhost:8001${cert.pdf_url}`} target="_blank" rel="noreferrer"
                style={{ textDecoration:"none" }}>
                <Btn t={t} onClick={() => {}}>
                  <Ic d={ICONS.external} size={14} color="#fff" />
                  Download PDF
                </Btn>
              </a>
            </div>
          )}
        </Card>
      )}
    </div>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
// CASE LAWS
// ══════════════════════════════════════════════════════════════════════════════
const CaseLaws = ({ t, toast }) => {
  const [q, setQ]           = useState("");
  const [loading, setLoad]  = useState(false);
  const [results, setRes]   = useState([]);

  const run = async () => {
    setLoad(true); setRes([]);
    try {
      const r = await fetch("http://localhost:8001/api/caselaws", {
        method:"POST", headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ query:q }),
      });
      if (!r.ok) throw new Error(`Server error ${r.status}`);
      const d = await r.json();
      setRes(d.results || []);
      if (!d.results?.length) toast("No results found", "warning");
    } catch(e) { toast(e.message, "error"); }
    finally { setLoad(false); }
  };

  return (
    <div style={{ maxWidth:820, margin:"0 auto", padding:"52px 24px" }}>
      <PageTitle icon="search" title="Case Laws"
        desc="Search Indian case law by topic. Results are pulled from IndianKanoon and summarised by Llama-3."
        t={t} />

      <Card t={t} style={{ marginBottom:20 }}>
        <div style={{ display:"flex", gap:8 }}>
          <Input value={q} onChange={e => setQ(e.target.value)}
            onKeyDown={e => e.key === "Enter" && run()}
            placeholder="e.g. IPC 498A bail conditions or cheque bounce notice period"
            t={t} />
          <Btn onClick={run} disabled={loading || !q} loading={loading} small t={t}>
            {!loading && <Ic d={ICONS.search} size={14} color="#fff" />}
          </Btn>
        </div>
      </Card>

      {loading && (
        <div style={{ textAlign:"center", padding:"48px 0", color:t.sub, fontSize:14 }}>
          <Spinner c={t.blue} /><br /><br />Searching IndianKanoon…
        </div>
      )}

      {results.length > 0 && (
        <div style={{ display:"flex", flexDirection:"column", gap:14 }}>
          <p style={{ fontSize:12, color:t.muted, margin:"0 0 4px" }}>{results.length} result{results.length > 1 ? "s" : ""}</p>
          {results.map((r,i) => (
            <Card t={t} key={i}>
              <div style={{ display:"flex", justifyContent:"space-between", alignItems:"flex-start", gap:12, marginBottom:8 }}>
                <h4 style={{ color:t.text, fontWeight:700, fontSize:15, margin:0, lineHeight:1.4 }}>{r.title || `Case ${i+1}`}</h4>
                {r.court && <Tag label={r.court} variant="info" t={t} />}
              </div>
              {r.date && <p style={{ fontSize:11, color:t.muted, margin:"0 0 10px" }}>{r.date}</p>}
              <p style={{ color:t.sub, fontSize:13, lineHeight:1.7, margin:"0 0 14px" }}>{r.snippet || r.summary || "No summary available."}</p>
              {r.url && (
                <a href={r.url} target="_blank" rel="noreferrer"
                  style={{ color:t.blue, fontSize:12, fontWeight:600, textDecoration:"none",
                    display:"inline-flex", alignItems:"center", gap:4 }}>
                  View judgment <Ic d={ICONS.external} size={12} color={t.blue} />
                </a>
              )}
            </Card>
          ))}
        </div>
      )}
    </div>
  );
};

