// NAV
// ══════════════════════════════════════════════════════════════════════════════
const Nav = ({ page, go, theme, toggle, t }) => {
  const [open, setOpen] = useState(false);
  const links = [
    { id:"home",       label:"Home" },
    { id:"analyzer",   label:"Analyzer" },
    { id:"compliance", label:"Compliance" },
    { id:"evidence",   label:"Evidence" },
    { id:"caselaws",   label:"Case Laws" },
  ];

  return (
    <>
      <nav style={{
        position:"fixed", top:0, left:0, right:0, zIndex:1000,
        background:t.nav, backdropFilter:"blur(12px)",
        borderBottom:`1px solid ${t.border}`,
        height:54, display:"flex", alignItems:"center",
        padding:"0 20px", justifyContent:"space-between",
      }}>
        <button onClick={() => go("home")} style={{ background:"none", border:"none", cursor:"pointer",
          display:"flex", alignItems:"center", gap:8, padding:0 }}>
          <Ic d={ICONS.scale} size={17} color={t.blue} />
          <span style={{ fontSize:15, fontWeight:800, color:t.text, letterSpacing:"-0.01em" }}>
            Nyaya<span style={{ color:t.blue }}>AI</span>
          </span>
        </button>

        {/* Desktop */}
        <div style={{ display:"flex", gap:2 }} className="dnav">
          {links.map(l => (
            <button key={l.id} onClick={() => go(l.id)} style={{
              background: page===l.id ? t.surfaceUp : "transparent",
              border:`1px solid ${page===l.id ? t.border : "transparent"}`,
              color: page===l.id ? t.text : t.sub,
              borderRadius:7, padding:"5px 12px", cursor:"pointer",
              fontSize:13, fontWeight:600, fontFamily:"inherit",
              transition:"all 0.12s",
            }}>{l.label}</button>
          ))}
        </div>

        <div style={{ display:"flex", gap:8, alignItems:"center" }}>
          <button onClick={toggle} style={{ background:t.surfaceUp, border:`1px solid ${t.border}`,
            borderRadius:7, padding:"6px 9px", cursor:"pointer",
            display:"flex", alignItems:"center", color:t.sub }}>
            <Ic d={ICONS[theme==="dark" ? "sun" : "moon"]} size={14} color={t.sub} />
          </button>
          <button onClick={() => setOpen(!open)} className="mnav"
            style={{ background:"none", border:"none", cursor:"pointer", color:t.sub, display:"none" }}>
            <Ic d={ICONS[open ? "x" : "menu"]} size={19} />
          </button>
        </div>
      </nav>

      {/* Mobile drawer */}
      {open && (
        <div style={{ position:"fixed", top:54, left:0, right:0, zIndex:999,
          background:t.surface, borderBottom:`1px solid ${t.border}`,
          padding:"8px 12px", display:"flex", flexDirection:"column", gap:2 }}>
          {links.map(l => (
            <button key={l.id} onClick={() => { go(l.id); setOpen(false); }}
              style={{ background: page===l.id ? t.surfaceUp : "transparent",
                border:"none", color: page===l.id ? t.text : t.sub,
                borderRadius:7, padding:"10px 14px", cursor:"pointer",
                fontSize:14, fontWeight:500, textAlign:"left", fontFamily:"inherit" }}>
              {l.label}
            </button>
          ))}
        </div>
      )}
    </>
  );
};

// ══════════════════════════════════════════════════════════════════════════════
// ROOT
// ══════════════════════════════════════════════════════════════════════════════
export default function App() {
  const [theme, setTheme] = useState("dark");
  const [page,  setPage]  = useState("home");
  const [toast, setToast] = useState(null);
  const t = theme === "dark" ? DARK : LIGHT;

  const showToast = (msg, type) => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 4000);
  };

  const pages = {
    home:       <Home       t={t} go={setPage} />,
    analyzer:   <Analyzer   t={t} toast={showToast} />,
    compliance: <Compliance t={t} toast={showToast} />,
    evidence:   <Evidence   t={t} toast={showToast} />,
    caselaws:   <CaseLaws   t={t} toast={showToast} />,
  };

  return (
    <div style={{ minHeight:"100vh", background:t.bg, color:t.text, fontFamily:"'Geist', 'Inter', system-ui, sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Geist:wght@400;500;600;700;800&display=swap');
        * { box-sizing:border-box; margin:0; padding:0; }
        @keyframes spin    { to { transform: rotate(360deg); } }
        @keyframes slideUp { from { transform:translateY(8px); opacity:0; } to { transform:translateY(0); opacity:1; } }
        input:focus, textarea:focus { border-color: #4f80ff !important; box-shadow: 0 0 0 3px #4f80ff22 !important; }
        button:hover:not(:disabled) { opacity: 0.88; }
        ::-webkit-scrollbar { width:5px; }
        ::-webkit-scrollbar-thumb { background:${t.border}; border-radius:3px; }
        @media (max-width:620px) { .dnav { display:none !important; } .mnav { display:flex !important; } }
      `}</style>

      <Nav page={page} go={setPage} theme={theme} toggle={() => setTheme(theme==="dark" ? "light" : "dark")} t={t} />
      <main style={{ paddingTop:54 }}>{pages[page]}</main>
      {toast && <Toast msg={toast.msg} type={toast.type} t={t} onClose={() => setToast(null)} />}
    </div>
  );
}
